module RefModule (  
    input wire clk,  
    input wire reset,  
    input wire [4:0] gpio_input,  
    output reg [4:0] gpio_output  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            gpio_output <= 5'b00000;  
        else  
            gpio_output <= gpio_input;  
    end  
endmodule
